var countBadPairs = function(nums) {
    const cnt = new Map();
    const n = nums.length;
    let good = 0;
    for (let i = 0; i < n; i++) {
        const key = nums[i] - i;
        const c = cnt.get(key) || 0;
        good += c;
        cnt.set(key, c + 1);
    }
    return n * (n - 1) / 2 - good;
};
